public static long solve(long n, long[][] edges, long k) {
    List<Edge> edgeList = new ArrayList<>();
    for (long[] e : edges) {
        edgeList.add(new Edge(e[0], e[1], e[2], e[3]));
    }

    // Separate must and optional edges
    List<Edge> mustEdges = new ArrayList<>();
    List<Edge> optionalEdges = new ArrayList<>();
    for (Edge e : edgeList) {
        if (e.must == 1) {
            mustEdges.add(e);
        } else {
            optionalEdges.add(e);
        }
    }

    // First, check if must edges form a cycle (using Union-Find)
    UnionFind uf = new UnionFind((int) n);
    for (Edge e : mustEdges) {
        if (uf.find((int) e.u) == uf.find((int) e.v)) {
            return -1; // cycle detected
        }
        uf.union((int) e.u, (int) e.v);
    }

    // Now, process optional edges in descending order of strength (after possible upgrade)
    // We want to maximize the minimal strength, so we prefer higher strength edges
    Collections.sort(optionalEdges, (a, b) -> Long.compare(b.s, a.s));

    // We can upgrade up to k edges, doubling their strength
    // To maximize the minimal strength, we should upgrade the top k edges with highest original strength
    for (int i = 0; i < Math.min(k, optionalEdges.size()); i++) {
        Edge e = optionalEdges.get(i);
        e.s *= 2;
    }

    // Now, sort all edges in descending order of strength (Krusky's algorithm for max-min)
    List<Edge> allEdges = new ArrayList<>();
    allEdges.addAll(mustEdges);
    allEdges.addAll(optionalEdges);
    Collections.sort(allEdges, (a, b) -> Long.compare(b.s, a.s));

    // Re-initialize Union-Find
    uf = new UnionFind((int) n);
    long minStrength = Long.MAX_VALUE;
    int edgesUsed = 0;

    for (Edge e : allEdges) {
        if (uf.find((int) e.u) != uf.find((int) e.v)) {
            uf.union((int) e.u, (int) e.v);
            minStrength = Math.min(minStrength, e.s);
            edgesUsed++;
            if (edgesUsed == n - 1) {
                break;
            }
        }
    }

    if (edgesUsed != n - 1) {
        return -1; // not connected
    }

    return minStrength;
}

