public static long solve(long n, long[][] edges, long k) {
    int nodeCount = (int) n;
    int upgradeLimit = (int) k;

    // Separate must and optional edges
    List<int[]> mustEdges = new ArrayList<>();
    List<int[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        int ui = (int) edge[0];
        int vi = (int) edge[1];
        int si = (int) edge[2];
        int musti = (int) edge[3];
        if (musti == 1) {
            mustEdges.add(new int[]{ui, vi, si});
        } else {
            optionalEdges.add(new int[]{ui, vi, si});
        }
    }

    // First, check if must edges form a forest without cycles
    UnionFind ufMust = new UnionFind(nodeCount);
    for (int[] edge : mustEdges) {
        int u = edge[0];
        int v = edge[1];
        if (ufMust.find(u) == ufMust.find(v)) {
            return -1; // cycle detected in must edges
        }
        ufMust.union(u, v);
    }

    // Now, collect all edges (must + optional) with possible upgrades
    List<int[]> allEdges = new ArrayList<>();
    for (int[] edge : mustEdges) {
        allEdges.add(new int[]{edge[0], edge[1], edge[2]});
    }
    for (int[] edge : optionalEdges) {
        allEdges.add(new int[]{edge[0], edge[1], edge[2]});
        allEdges.add(new int[]{edge[0], edge[1], edge[2] * 2}); // upgraded version
    }

    // Binary search for the maximum possible min strength
    int left = 0;
    int right = (int) 1e5 * 2;
    int result = -1;

    while (left <= right) {
        int mid = (left + right) / 2;
        if (canFormSpanningTree(nodeCount, allEdges, mustEdges, optionalEdges, upgradeLimit, mid)) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
}

static class UnionFind {
    int[] parent;
    int[] rank;

    public UnionFind(int size) {
        parent = new int[size];
        rank = new int[size];
        for (int i = 0; i < size; i++) {
            parent[i] = i;
        }
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public void union(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);
        if (xRoot == yRoot) return;
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else if (rank[yRoot] < rank[xRoot]) {
            parent[yRoot] = xRoot;
        } else {
            parent[yRoot] = xRoot;
            rank[xRoot]++;
        }
    }
}

private static boolean canFormSpanningTree(int nodeCount, List<int[]> allEdges, List<int[]> mustEdges, List<int[]> optionalEdges, int upgradeLimit, int minStrength) {
    UnionFind uf = new UnionFind(nodeCount);
    int usedUpgrades = 0;

    // First, add all must edges with strength >= minStrength
    for (int[] edge : mustEdges) {
        int u = edge[0];
        int v = edge[1];
        int s = edge[2];
        if (s >= minStrength) {
            uf.union(u, v);
        }
    }

    // Then, add optional edges (original or upgraded) with strength >= minStrength, prioritizing upgraded ones first
    List<int[]> filteredOptional = new ArrayList<>();
    for (int[] edge : optionalEdges) {
        int u = edge[0];
        int v = edge[1];
        int s = edge[2];
        if (s * 2 >= minStrength) {
            filteredOptional.add(new int[]{u, v, s * 2, 1}); // upgraded
        }
        if (s >= minStrength) {
            filteredOptional.add(new int[]{u, v, s, 0}); // original
        }
    }

    // Sort optional edges in descending order of strength (to maximize min strength)
    filteredOptional.sort((a, b) -> Integer.compare(b[2], a[2]));

    for (int[] edge : filteredOptional) {
        int u = edge[0];
        int v = edge[1];
        int s = edge[2];
        int isUpgraded = edge[3];
        if (uf.find(u) != uf.find(v)) {
            if (isUpgraded == 1) {
                if (usedUpgrades >= upgradeLimit) {
                    continue;
                }
                usedUpgrades++;
            }
            uf.union(u, v);
        }
    }

    // Check if all nodes are connected
    int root = uf.find(0);
    for (int i = 1; i < nodeCount; i++) {
        if (uf.find(i) != root) {
            return false;
        }
    }
    return true;
}
