    // Process must edges first
    int components = (int)n;
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        if (s < minStrength) {
            return false; // must edge doesn't meet the requirement
        }
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU != rootV) {
            parent[(int)rootV] = rootU;
            components--;
        }
    }

    if (components == 1) {
        return true; // already connected
    }

    // Process optional edges, sorted by max possible strength (after upgrade)
    // We want to pick edges that can meet minStrength, using upgrades if needed
    List<long[]> candidates = new ArrayList<>();
    for (long[] edge : optionalEdges) {
        long s = edge[2];
        if (s >= minStrength) {
            candidates.add(new long[]{edge[0], edge[1], s, 0}); // no upgrade needed
        } else if (s * 2 >= minStrength) {
            candidates.add(new long[]{edge[0], edge[1], s * 2, 1}); // upgrade needed
        }
    }

    // Sort by upgrade cost (0 first, then 1)
    candidates.sort((a, b) -> Long.compare(a[3], b[3]));

    long upgradesUsed = 0;
    for (long[] edge : candidates) {
        if (components == 1) {
            break;
        }
        long u = edge[0];
        long v = edge[1];
        long cost = edge[3];
        if (upgradesUsed + cost > k) {
            continue;
        }
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU != rootV) {
            parent[(int)rootV] = rootU;
            components--;
            upgradesUsed += cost;
        }
    }

    return components == 1;
}

private static long find(long[] parent, long u) {
    if (parent[(int)u] != u) {
        parent[(int)u] = find(parent, parent[(int)u]);
    }
    return parent[(int)u];
}
