                mustEdges.add(e);
            } else {
                nonMustEdges.add(e);
            }
        }

        // Sort non-must edges in descending order of strength (before upgrade)
        Collections.sort(nonMustEdges, (a, b) -> Long.compare(b.s, a.s));

        // Use Union-Find to check connectivity and build the initial spanning tree with must edges
        UnionFind uf = new UnionFind(n);
        long minStrength = Long.MAX_VALUE;
        int mustCount = 0;

        for (Edge e : mustEdges) {
            if (uf.union(e.u, e.v)) {
                mustCount++;
                minStrength = Math.min(minStrength, e.s);
            } else {
                // Must edges form a cycle, impossible to have a spanning tree
                return -1;
            }
        }

        // Now add non-must edges, possibly upgrading some
        long remainingK = k;
        PriorityQueue<Edge> pq = new PriorityQueue<>((a, b) -> Long.compare(b.upgradedS(), a.upgradedS()));
        pq.addAll(nonMustEdges);

        while (!pq.isEmpty() && mustCount < n - 1) {
            Edge e = pq.poll();
            if (uf.union(e.u, e.v)) {
                mustCount++;
                if (remainingK > 0) {
                    remainingK--;
                    minStrength = Math.min(minStrength, e.s * 2);
                } else {
                    minStrength = Math.min(minStrength, e.s);
                }
            }
        }

        if (mustCount != n - 1) {
            return -1;
        }

        return minStrength;
    }

