public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Separate must edges and optional edges
        List<long[]> mustEdges = new ArrayList<>();
        List<long[]> optionalEdges = new ArrayList<>();
        for (long[] edge : edges) {
            if (edge[3] == 1) {
                mustEdges.add(edge);
            } else {
                optionalEdges.add(edge);
            }
        }

        // First, check if the must edges form a valid forest (no cycles)
        UnionFind ufMust = new UnionFind((int) n);
        for (long[] edge : mustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            if (ufMust.union(u, v)) {
                // If union returns true, it means a cycle was detected
                return -1;
            }
        }

        // Now, build the initial MST with must edges
        UnionFind uf = new UnionFind((int) n);
        for (long[] edge : mustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            uf.union(u, v);
        }

        // If the must edges already connect all nodes, find the min strength among them
        if (uf.getCount() == 1) {
            long minStrength = Long.MAX_VALUE;
            for (long[] edge : mustEdges) {
                minStrength = Math.min(minStrength, edge[2]);
            }
            return minStrength;
        }

        // Sort optional edges in descending order of strength (after potential upgrade)
        // We'll consider upgrading the strongest edges first to maximize the min strength
        Collections.sort(optionalEdges, (a, b) -> {
            long aUpgraded = a[2] * 2;
            long bUpgraded = b[2] * 2;
            return Long.compare(bUpgraded, aUpgraded);
        });

        // Now, try to add optional edges (possibly upgraded) to connect the graph
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[2], b[2]));
        List<long[]> selectedEdges = new ArrayList<>(mustEdges);

        // Add all must edges to the PQ to find the initial min strength
        for (long[] edge : mustEdges) {
            pq.offer(edge);
        }

        int upgradesUsed = 0;
        for (long[] edge : optionalEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            if (uf.union(u, v)) {
                // Decide whether to upgrade this edge
                if (upgradesUsed < k) {
                    long upgradedStrength = edge[2] * 2;
                    long[] upgradedEdge = new long[]{edge[0], edge[1], upgradedStrength, edge[3]};
                    selectedEdges.add(upgradedEdge);
                    pq.offer(upgradedEdge);
                    upgradesUsed++;
                } else {
                    selectedEdges.add(edge);
                    pq.offer(edge);
                }
            }
            if (uf.getCount() == 1) {
                break;
            }
        }

        // Check if all nodes are connected
        if (uf.getCount() != 1) {
            return -1;
        }

        // The min strength in the selected edges is the answer
        long minStrength = Long.MAX_VALUE;
        for (long[] edge : selectedEdges) {
            minStrength = Math.min(minStrength, edge[2]);
        }
        return minStrength;
    }

    static class UnionFind {
        private int[] parent;
        private int[] rank;
        private int count;

        public UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public boolean union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) {
                return true; // indicates a cycle
            }
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            count--;
            return false;
        }

        public int getCount() {
            return count;
        }
    }
