    // We want to maximize the minimal strength, so we should prioritize edges with higher strength
    // Also, we can upgrade some edges to increase their strength

    // Sort optional edges by descending strength (after potential upgrade)
    Collections.sort(optionalEdges, (a, b) -> Long.compare(b.s * 2, a.s * 2));

    UnionFind ufFinal = new UnionFind(n);
    // Add must edges first
    for (Edge e : mustEdges) {
        ufFinal.union(e.u, e.v);
    }

    long remainingK = k;
    long minStrength = Long.MAX_VALUE;

    // Process must edges to find the current min strength
    for (Edge e : mustEdges) {
        if (e.s < minStrength) {
            minStrength = e.s;
        }
    }

    // Now add optional edges, possibly upgrading them
    for (Edge e : optionalEdges) {
        if (ufFinal.find(e.u) != ufFinal.find(e.v)) {
            long strength = e.s;
            if (remainingK > 0) {
                strength *= 2;
                remainingK--;
            }
            ufFinal.union(e.u, e.v);
            if (strength < minStrength) {
                minStrength = strength;
            }
        }
    }

    // Check if all nodes are connected
    long root = ufFinal.find(0);
    for (long i = 1; i < n; i++) {
        if (ufFinal.find(i) != root) {
            return -1;
        }
    }

    return minStrength;
}

static class Edge {
    long u, v, s, must;
    Edge(long u, long v, long s, long must) {
        this.u = u;
        this.v = v;
        this.s = s;
        this.must = must;
    }
}

