    public static long solve(long n, long[][] edges, long k) {
        List<Edge> edgeList = new ArrayList<>();
        for (long[] edge : edges) {
            edgeList.add(new Edge(edge[0], edge[1], edge[2], edge[3]));
        }
        // Separate must and non-must edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> nonMustEdges = new ArrayList<>();
        for (Edge e : edgeList) {
            if (e.must == 1) {
                mustEdges.add(e);
            } else {
                nonMustEdges.add(e);
            }
        }

        // First, check if must edges form a cycle
        UnionFind uf = new UnionFind(n);
        for (Edge e : mustEdges) {
            if (uf.find(e.u) == uf.find(e.v)) {
                return -1; // cycle detected in must edges
            }
            uf.union(e.u, e.v);
        }

        // Now, process non-must edges in descending order of strength (after possible upgrade)
        // We want to maximize the minimal strength, so we should prioritize edges with higher strength
        // Sort non-must edges in descending order of max possible strength (original or doubled)
        nonMustEdges.sort((a, b) -> {
            long aMax = a.s * 2;
            long bMax = b.s * 2;
            return Long.compare(bMax, aMax);
        });

        // We can use up to k upgrades on non-must edges to maximize the minimal strength
        // The strategy is to use upgrades on the top k edges (after sorting) to maximize their strength
        // Then, include them in the spanning tree if they connect different components

        // Reset UnionFind to include must edges first
        uf = new UnionFind(n);
        for (Edge e : mustEdges) {
            uf.union(e.u, e.v);
        }

        // Now, process non-must edges, using upgrades on the first k edges that are actually used in the spanning tree
        PriorityQueue<Edge> pq = new PriorityQueue<>((a, b) -> Long.compare(a.s, b.s)); // min-heap to track the minimal strength
        int upgradesUsed = 0;

        // Add must edges to the priority queue first
        for (Edge e : mustEdges) {
            pq.add(e);
        }

        // Process non-must edges in sorted order
        for (Edge e : nonMustEdges) {
            if (uf.find(e.u) != uf.find(e.v)) {
                // Decide whether to upgrade this edge
                if (upgradesUsed < k) {
                    Edge upgraded = new Edge(e.u, e.v, e.s * 2, e.must);
                    pq.add(upgraded);
                    upgradesUsed++;
                } else {
                    pq.add(e);
                }
                uf.union(e.u, e.v);
            }
        }

        // Check if all nodes are connected
        if (uf.getNumComponents() != 1) {
            return -1;
        }

        // The minimal strength in the priority queue is the answer
        return pq.peek().s;
    }

    static class Edge {
        long u, v, s, must;
        Edge(long u, long v, long s, long must) {
            this.u = u;
            this.v = v;
            this.s = s;
            this.must = must;
        }
    }

