        private long[] rank;
        private long numComponents;

        UnionFind(long n) {
            parent = new long[(int)n];
            rank = new long[(int)n];
            numComponents = n;
            for (long i = 0; i < n; i++) {
                parent[(int)i] = i;
                rank[(int)i] = 0;
            }
        }

