        int v = (int) edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // cycle detected
        }
        uf.union(u, v);
    }

    // Now, process optional edges in descending order of strength (after possible upgrade)
    // We need to select edges that can maximize the minimal strength in the spanning tree
    // So we should prioritize edges with higher strength (after possible upgrade)

    // Create a list of optional edges with their possible upgraded strength
    List<Edge> upgradedEdges = new ArrayList<>();
    for (long[] edge : optionalEdges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        upgradedEdges.add(new Edge(u, v, s, s * 2));
    }

    // Sort the edges in descending order of max possible strength (max(s, 2*s))
    Collections.sort(upgradedEdges, (a, b) -> Long.compare(b.maxStrength, a.maxStrength));

    // Binary search to find the maximum minimal strength
    long left = 1;
    long right = (long) 1e10;
    long result = -1;

    while (left <= right) {
        long mid = left + (right - left) / 2;
        if (canFormSpanningTree((int) n, mustEdges, upgradedEdges, k, mid)) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
}

private static boolean canFormSpanningTree(int n, List<long[]> mustEdges, List<Edge> optionalEdges, long k, long minStrength) {
    UnionFind uf = new UnionFind(n);

    // First, add all must edges (they are already checked for no cycle)
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];
        if (s < minStrength) {
            return false; // must edge doesn't meet the minStrength
        }
        uf.union(u, v);
    }

    long upgradesUsed = 0;

    // Then, add optional edges that can meet the minStrength (possibly with upgrade)
    for (Edge edge : optionalEdges) {
        int u = (int) edge.u;
        int v = (int) edge.v;
        long original = edge.originalStrength;
        long upgraded = edge.upgradedStrength;

        if (uf.find(u) == uf.find(v)) {
            continue; // already connected
        }

        if (upgraded >= minStrength) {
            // Prefer to use upgraded if possible (since we sorted in descending order)
            uf.union(u, v);
            if (original < minStrength) {
                upgradesUsed++;
            }
        } else if (original >= minStrength) {
            uf.union(u, v);
        } else {
            continue; // cannot meet minStrength
        }

        if (upgradesUsed > k) {
            return false;
        }
    }

    return uf.count == 1; // all nodes connected
}

