import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        int nodeCount = (int) n;
        int upgradeBudget = (int) k;
        List<Edge> allEdges = new ArrayList<>();
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int must = (int) edge[3];
            Edge e = new Edge(u, v, s, must);
            allEdges.add(e);
            if (must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // First, check if the must edges form a cycle
        UnionFind ufMust = new UnionFind(nodeCount);
        for (Edge e : mustEdges) {
            if (ufMust.union(e.u, e.v)) {
                // Cycle detected with must edges
                return -1;
            }
        }

        // Now, we need to select optional edges to complete the spanning tree
        // We want to maximize the minimum strength, so we should prioritize higher strength edges
        // Also, we can upgrade some edges to increase their strength

        // Sort optional edges by descending strength (original)
        Collections.sort(optionalEdges, (a, b) -> Integer.compare(b.s, a.s));

        // We can upgrade up to k edges to double their strength
        // To maximize the minimum strength, we should upgrade the strongest edges first
        // So we can consider the upgraded strength when selecting edges

        // Binary search for the maximum possible minimum strength
        int low = 1;
        int high = (int) 2e5; // since original s can be up to 1e5, and doubled is 2e5
        long result = -1;

        while (low <= high) {
            int mid = (low + high) / 2;
            if (isPossible(nodeCount, mustEdges, optionalEdges, upgradeBudget, mid)) {
                result = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        return result;
    }

    private static boolean isPossible(int nodeCount, List<Edge> mustEdges, List<Edge> optionalEdges, int upgradeBudget, int targetMin) {
        UnionFind uf = new UnionFind(nodeCount);
        int usedUpgrades = 0;

        // First, add all must edges (they cannot be upgraded)
        for (Edge e : mustEdges) {
            uf.union(e.u, e.v);
        }

        // Then, add optional edges that can meet the targetMin without upgrade
        for (Edge e : optionalEdges) {
            if (e.s >= targetMin) {
                uf.union(e.u, e.v);
            }
        }

        // If already connected, no need to use upgrades
        if (uf.components == 1) {
            return true;
        }

        // Otherwise, try to use upgrades on edges that can meet targetMin when doubled
        uf = new UnionFind(nodeCount);
        for (Edge e : mustEdges) {
            uf.union(e.u, e.v);
        }

        usedUpgrades = 0;
        for (Edge e : optionalEdges) {
            if (e.s >= targetMin) {
                uf.union(e.u, e.v);
            } else if (e.s * 2 >= targetMin && usedUpgrades < upgradeBudget) {
                uf.union(e.u, e.v);
                usedUpgrades++;
            }
        }

        return uf.components == 1;
    }

    static class Edge {
        int u, v, s, must;
        Edge(int u, int v, int s, int must) {
            this.u = u;
            this.v = v;
            this.s = s;
            this.must = must;
        }
    }

    static class UnionFind {
        int[] parent;
        int[] rank;
        int components;

        UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            components = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        boolean union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) {
                return true; // cycle detected
            }
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            components--;
            return false;
        }
