        long rootV = find(parent, v);
        if (rootU != rootV) {
            if (isUpgraded == 1) {
                if (upgradesUsed >= k) continue;
                upgradesUsed++;
            }
            parent[(int)rootV] = rootU;
            minStrength = Math.min(minStrength, s);
            remainingEdges--;
        }
    }

    if (remainingEdges != 0) {
        return -1; // couldn't connect all nodes
    }

    return minStrength;
}

private static long find(long[] parent, long node) {
    if (parent[(int)node] != node) {
        parent[(int)node] = find(parent, parent[(int)node]);
    }
    return parent[(int)node];
}
