        }
        uf.union((int) e.u, (int) e.v);
    }

    long upgradesUsed = 0;

    // Add optional edges that can meet minStrength (possibly with upgrade)
    for (Edge e : optionalEdges) {
        if (uf.getCount() == 1) break; // already connected

        long original = e.s;
        long upgraded = e.s * 2;

        boolean canUse = false;
        long strengthToUse = -1;

        if (original >= minStrength) {
            canUse = true;
