public static long solve(long n, long[][] edges, long k) {
    // Separate must and optional edges
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // Check if must edges form a cycle (using Union-Find)
    UnionFind uf = new UnionFind(n);
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // cycle detected with must edges
        }
        uf.union(u, v);
    }

    // Now process optional edges, sorted by descending strength (after potential upgrade)
    // We want to pick edges with highest possible strength to maximize the min strength
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> {
        long aStrength = a[2] * (a[3] == 0 ? 2 : 1); // if upgradable, consider doubled strength
        long bStrength = b[2] * (b[3] == 0 ? 2 : 1);
        return Long.compare(bStrength, aStrength); // max heap
    });

    for (long[] edge : optionalEdges) {
        pq.add(edge);
    }

    // Now select optional edges to complete the spanning tree
    int remaining = (int) (n - 1 - mustEdges.size());
    if (remaining < 0) {
        return -1; // too many must edges
    }

    List<Long> selectedStrengths = new ArrayList<>();
    for (long[] edge : mustEdges) {
        selectedStrengths.add(edge[2]);
    }

    int upgradesUsed = 0;
    while (remaining > 0 && !pq.isEmpty()) {
        long[] edge = pq.poll();
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        boolean must = edge[3] == 1;

        if (uf.find(u) != uf.find(v)) {
            // Decide whether to upgrade this edge
            if (!must && upgradesUsed < k) {
                s *= 2;
                upgradesUsed++;
            }
            selectedStrengths.add(s);
            uf.union(u, v);
            remaining--;
        }
    }

    if (remaining > 0 || selectedStrengths.size() != n - 1) {
        return -1; // no spanning tree possible
    }

    // Find the min strength in the selected edges
    long minStrength = Long.MAX_VALUE;
    for (long s : selectedStrengths) {
        if (s < minStrength) {
            minStrength = s;
        }
    }

    return minStrength;
}

