        for (long[] edge : mustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            uf.union(u, v);
        }

        // Now, try to add non-must edges with strength >= minStrength, possibly upgrading
        long upgradesUsed = 0;
        for (long[] edge : nonMustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long s = edge[2];
            if (s >= minStrength) {
                if (uf.find(u) != uf.find(v)) {
                    uf.union(u, v);
                }
            } else if (2 * s >= minStrength && upgradesUsed < k) {
                if (uf.find(u) != uf.find(v)) {
                    uf.union(u, v);
                    upgradesUsed++;
                }
            }
        }

