public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Convert input to more manageable types
        int numNodes = (int) n;
        int numEdges = edges.length;
        int upgradesLeft = (int) k;

        // Separate must and optional edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int must = (int) edge[3];
            Edge e = new Edge(u, v, s);
            if (must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // Sort optional edges in descending order of strength
        Collections.sort(optionalEdges, (a, b) -> Integer.compare(b.s, a.s));

        // First, check if must edges alone form a spanning tree (without cycles)
        UnionFind ufMust = new UnionFind(numNodes);
        for (Edge e : mustEdges) {
            ufMust.union(e.u, e.v);
        }
        if (ufMust.components == 1) {
            // Must edges form a spanning tree, find min strength among must edges
            int minStrength = Integer.MAX_VALUE;
            for (Edge e : mustEdges) {
                minStrength = Math.min(minStrength, e.s);
            }
            return minStrength;
        }

        // If must edges have cycles, return -1
        int totalEdgesInMust = mustEdges.size();
        if (totalEdgesInMust > numNodes - 1) {
            return -1;
        }

        // Now, try to build a spanning tree with must edges and optional edges
        UnionFind uf = new UnionFind(numNodes);
        for (Edge e : mustEdges) {
            uf.union(e.u, e.v);
        }

        // We need to add (numNodes - 1 - mustEdges.size()) optional edges
        int edgesNeeded = numNodes - 1 - mustEdges.size();
        if (edgesNeeded < 0) {
            return -1;
        }

        // Select the strongest optional edges first, possibly upgrading them
        List<Edge> selectedOptionalEdges = new ArrayList<>();
        for (Edge e : optionalEdges) {
            if (edgesNeeded <= 0) {
                break;
            }
            if (uf.union(e.u, e.v)) {
                selectedOptionalEdges.add(e);
                edgesNeeded--;
            }
        }

        if (edgesNeeded > 0) {
            return -1; // Could not form spanning tree
        }

        // Now, we have a spanning tree. The stability is min of:
        // 1. min strength among must edges
        // 2. min strength among selected optional edges (possibly upgraded)

        int minMustStrength = Integer.MAX_VALUE;
        for (Edge e : mustEdges) {
            minMustStrength = Math.min(minMustStrength, e.s);
        }

        if (selectedOptionalEdges.isEmpty()) {
            return minMustStrength;
        }

        // Sort selected optional edges by strength (ascending) to prioritize upgrading the smallest
        Collections.sort(selectedOptionalEdges, (a, b) -> Integer.compare(a.s, b.s));

        // Use upgrades on the smallest selected optional edges
        for (Edge e : selectedOptionalEdges) {
            if (upgradesLeft > 0) {
                e.s *= 2;
                upgradesLeft--;
            }
        }

        int minOptionalStrength = Integer.MAX_VALUE;
        for (Edge e : selectedOptionalEdges) {
            minOptionalStrength = Math.min(minOptionalStrength, e.s);
        }

        return Math.min(minMustStrength, minOptionalStrength);
    }

    static class Edge {
        int u, v, s;
        Edge(int u, int v, int s) {
            this.u = u;
            this.v = v;
            this.s = s;
        }
    }

    static class UnionFind {
        int[] parent;
        int[] rank;
        int components;

        UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            components = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        boolean union(int x, int y) {
            int xRoot = find(x);
            int yRoot = find(y);
            if (xRoot == yRoot) {
                return false;
            }
            if (rank[xRoot] < rank[yRoot]) {
                parent[xRoot] = yRoot;
            } else if (rank[xRoot] > rank[yRoot]) {
                parent[yRoot] = xRoot;
            } else {
                parent[yRoot] = xRoot;
                rank[xRoot]++;
            }
            components--;
            return true;
        }
    }
}
