        // If still not connected, use upgrades
        for (Edge e : optionalEdges) {
            if (upgradesUsed >= upgradesLeft) {
                break;
            }
            if (e.s * 2 >= minStrength) {
                if (uf.union(e.u, e.v)) {
                    upgradesUsed++;
                }
            }
        }

        return uf.components == 1;
    }

