        UnionFind uf = new UnionFind((int) n);
        for (Edge e : mustEdges) {
            if (uf.find(e.u) == uf.find(e.v)) {
                return -1; // cycle detected with must edges
            }
            uf.union(e.u, e.v);
        }

        // Now, process optional edges, sorted by descending strength (after potential upgrade)
        // We want to maximize the minimal strength, so prefer higher strength edges
        Collections.sort(optionalEdges, (a, b) -> {
            long aStrength = a.s * 2; // if upgraded
            long bStrength = b.s * 2; // if upgraded
            return Long.compare(bStrength, aStrength); // descending
        });

        // We can use up to k upgrades on the best optional edges
        UnionFind ufFinal = new UnionFind((int) n);
        // Add must edges first
        for (Edge e : mustEdges) {
            ufFinal.union(e.u, e.v);
        }

        long remainingK = k;
        long minStrength = Long.MAX_VALUE;

        // Track the edges used in the spanning tree
        List<Edge> usedEdges = new ArrayList<>();
        usedEdges.addAll(mustEdges);

        // Process optional edges, try to use upgraded ones first
        for (Edge e : optionalEdges) {
            if (ufFinal.find(e.u) != ufFinal.find(e.v)) {
                long currentStrength = e.s;
                if (remainingK > 0) {
                    currentStrength *= 2;
                    remainingK--;
                }
                usedEdges.add(e);
                minStrength = Math.min(minStrength, currentStrength);
                ufFinal.union(e.u, e.v);
            }
        }

        // Check if all nodes are connected
        if (ufFinal.getCount() != 1) {
            return -1;
        }

        // Now, find the minimal strength in the spanning tree
        minStrength = Long.MAX_VALUE;
        for (Edge e : mustEdges) {
            minStrength = Math.min(minStrength, e.s);
        }
        for (Edge e : usedEdges) {
            if (!e.must) {
                long strength = e.s;
                if (k > 0) {
                    strength *= 2;
                    k--;
                }
                minStrength = Math.min(minStrength, strength);
            }
        }

        return minStrength;
    }

