public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        int nodeCount = (int) n;
        int upgradeQuota = (int) k;

        // Separate must and optional edges
        List<int[]> mustEdges = new ArrayList<>();
        List<int[]> optionalEdges = new ArrayList<>();
        for (long[] edge : edges) {
            int ui = (int) edge[0];
            int vi = (int) edge[1];
            int si = (int) edge[2];
            int musti = (int) edge[3];
            if (musti == 1) {
                mustEdges.add(new int[]{ui, vi, si});
            } else {
                optionalEdges.add(new int[]{ui, vi, si});
            }
        }

        // First, check if must edges form a cycle (using Union-Find)
        UnionFind uf = new UnionFind(nodeCount);
        for (int[] edge : mustEdges) {
            int u = edge[0];
            int v = edge[1];
            if (uf.find(u) == uf.find(v)) {
                return -1; // cycle detected with must edges
            }
            uf.union(u, v);
        }

        // Now, process optional edges with possible upgrades
        // Sort optional edges in descending order of si
        optionalEdges.sort((a, b) -> Integer.compare(b[2], a[2]));

        // We need to select (nodeCount - 1 - mustEdges.size()) edges from optional edges
        int edgesNeeded = nodeCount - 1 - mustEdges.size();
        if (edgesNeeded < 0) {
            return -1; // too many must edges
        }

        // We can upgrade up to k edges (but only optional edges)
        // To maximize the minimal si, we should upgrade the largest possible si edges first
        PriorityQueue<Integer> upgradedEdges = new PriorityQueue<>();
        UnionFind ufFinal = new UnionFind(nodeCount);
        // First add all must edges
        for (int[] edge : mustEdges) {
            ufFinal.union(edge[0], edge[1]);
        }

        // Then add optional edges, possibly upgrading some
        int upgradesUsed = 0;
        List<Integer> selectedEdges = new ArrayList<>();
        for (int[] edge : optionalEdges) {
            int u = edge[0];
            int v = edge[1];
            int si = edge[2];
            if (ufFinal.find(u) != ufFinal.find(v)) {
                if (upgradesUsed < upgradeQuota) {
                    selectedEdges.add(si * 2);
                    upgradesUsed++;
                } else {
                    selectedEdges.add(si);
                }
                ufFinal.union(u, v);
            }
            if (selectedEdges.size() == edgesNeeded) {
                break;
            }
        }

        if (selectedEdges.size() < edgesNeeded || ufFinal.getComponents() > 1) {
            return -1; // not enough edges to form spanning tree
        }

        // The minimal edge in the spanning tree is the answer
        // Must edges are not upgraded, so their si is as is
        int minStability = Integer.MAX_VALUE;
        for (int[] edge : mustEdges) {
            minStability = Math.min(minStability, edge[2]);
        }
        for (int si : selectedEdges) {
            minStability = Math.min(minStability, si);
        }

        return minStability;
    }

    static class UnionFind {
