        while (parent[u.intValue()] != u) {
            parent[u.intValue()] = parent[(int)parent[u.intValue()]];
            u = parent[u.intValue()];
        }
        return u;
    };

    // Process must edges first
    int mustCount = 0;
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        long rootU = find.apply(u);
        long rootV = find.apply(v);
        if (rootU != rootV) {
