    List<long[]> upgradedEdges = new ArrayList<>();
    for (long[] edge : optionalEdges) {
        upgradedEdges.add(new long[]{edge[0], edge[1], edge[2] * 2, 0});
    }

    // Merge and sort all optional edges (original and upgraded)
    List<long[]> allOptionalEdges = new ArrayList<>();
    allOptionalEdges.addAll(optionalEdges);
    allOptionalEdges.addAll(upgradedEdges);
    allOptionalEdges.sort((a, b) -> Long.compare(b[2], a[2]));

    // Now, select edges to form the spanning tree, prioritizing higher strength
    // We can use up to k upgrades
    long remainingK = k;
    long minStrength = Long.MAX_VALUE;
    int selectedEdges = 0;

    // Reset Union-Find for the optional edges selection
    parent = new long[(int)n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    // First, connect must edges again (since we reset parent)
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        long rootU = find.apply(u);
        long rootV = find.apply(v);
        if (rootU != rootV) {
            parent[(int)rootV] = rootU;
        }
        minStrength = Math.min(minStrength, edge[2]);
    }

    // Now select optional edges
    for (long[] edge : allOptionalEdges) {
        if (selectedEdges + mustCount == n - 1) {
            break;
        }
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        long rootU = find.apply(u);
        long rootV = find.apply(v);
        if (rootU != rootV) {
