            boolean isUpgraded = (edge[3] == 0 && s == edge[2] * 2);
            if (isUpgraded) {
                if (remainingK > 0) {
                    remainingK--;
                    parent[(int)rootV] = rootU;
                    selectedEdges++;
                    minStrength = Math.min(minStrength, s);
                }
            } else {
                parent[(int)rootV] = rootU;
                selectedEdges++;
                minStrength = Math.min(minStrength, s);
