public static long solve(long n, long[][] edges, long k) {
    // Separate must edges and optional edges
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // First, check if must edges form a cycle (using Union-Find)
    UnionFind uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // cycle detected with must edges
        }
        uf.union(u, v);
    }

    // Now, we need to add optional edges to complete the spanning tree
    // We want to maximize the minimum strength, so we should prioritize edges with higher strength (after possible upgrade)

    // Sort optional edges in descending order of max possible strength (either s or 2*s if upgraded)
    Collections.sort(optionalEdges, (a, b) -> {
        long maxA = Math.max(a[2], 2 * a[2]);
        long maxB = Math.max(b[2], 2 * b[2]);
        return Long.compare(maxB, maxA);
    });

    // We can use up to k upgrades on the best edges
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[2], b[2]));

    // Add must edges to the priority queue first (they cannot be upgraded)
    for (long[] edge : mustEdges) {
        pq.offer(new long[]{edge[0], edge[1], edge[2]});
    }

    int upgradesUsed = 0;
    // Process optional edges
    for (long[] edge : optionalEdges) {
        if (uf.find((int) edge[0]) != uf.find((int) edge[1])) {
            // Decide whether to upgrade this edge
            long strength = edge[2];
            if (upgradesUsed < k) {
                strength *= 2;
                upgradesUsed++;
            }
            pq.offer(new long[]{edge[0], edge[1], strength});
            uf.union((int) edge[0], (int) edge[1]);
        }
    }

    // Check if all nodes are connected
    if (uf.getCount() != 1) {
        return -1;
    }

    // The stability is the minimum strength in the spanning tree
    long minStrength = Long.MAX_VALUE;
    while (!pq.isEmpty()) {
        long[] edge = pq.poll();
        minStrength = Math.min(minStrength, edge[2]);
    }

    return minStrength;
}

static class UnionFind {
    private int[] parent;
    private int[] rank;
    private int count;

    public UnionFind(int n) {
        parent = new int[n];
        rank = new int[n];
        count = n;
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
    }

    public int find(int p) {
        while (p != parent[p]) {
            parent[p] = parent[parent[p]];
            p = parent[p];
        }
        return p;
    }

    public void union(int p, int q) {
        int rootP = find(p);
        int rootQ = find(q);
        if (rootP == rootQ) return;

        if (rank[rootP] > rank[rootQ]) {
            parent[rootQ] = rootP;
        } else if (rank[rootP] < rank[rootQ]) {
            parent[rootP] = rootQ;
        } else {
            parent[rootQ] = rootP;
            rank[rootP]++;
        }
        count--;
    }

    public int getCount() {
        return count;
    }
}
