    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU == rootV) {
            return -1; // cycle detected with must edges
        }
        parent[(int)rootV] = rootU;
        mustCount++;
    }

    // Now process optional edges, considering possible upgrades
    // We want to maximize the minimal strength, so we should prioritize edges with higher strength (after possible upgrade)
    // Sort optional edges in descending order of max possible strength (either s_i or 2*s_i)
    Collections.sort(optionalEdges, (a, b) -> {
        long maxA = Math.max(a[2], 2 * a[2]);
        long maxB = Math.max(b[2], 2 * b[2]);
        return Long.compare(maxB, maxA);
    });

    // Use Union-Find to build the spanning tree, using up to k upgrades
    int upgradesUsed = 0;
    List<Long> strengths = new ArrayList<>();

    // Add strengths of must edges
    for (long[] edge : mustEdges) {
        strengths.add(edge[2]);
    }

    // Process optional edges
    for (long[] edge : optionalEdges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU != rootV) {
            parent[(int)rootV] = rootU;
            // Decide whether to upgrade this edge
            if (upgradesUsed < k) {
                strengths.add(2 * s);
                upgradesUsed++;
            } else {
                strengths.add(s);
            }
        }
    }

    // Check if we have a spanning tree (must have exactly n-1 edges)
    if (strengths.size() != n - 1) {
        return -1;
    }

    // The stability is the minimal strength in the spanning tree
    long minStrength = Collections.min(strengths);
    return minStrength;
}

private static long find(long[] parent, long node) {
    if (parent[(int)node] != node) {
        parent[(int)node] = find(parent, parent[(int)node]);
    }
    return parent[(int)node];
