            }
            uf2.union(u, v);
            minStrength = Math.min(minStrength, strength);
        }
    }

    if (uf2.count != 1) {
        return -1; // no spanning tree possible
    }

    // Also, consider the must edges' strengths
    for (long[] edge : mustEdges) {
        minStrength = Math.min(minStrength, edge[2]);
    }

    return minStrength;
}

