        }
        uf.union(u, v);
    }

    // Now, process optional edges in descending order of si (after potential upgrade)
    // We want to maximize the minimum strength, so we should prioritize edges with higher si
    PriorityQueue<int[]> maxHeap = new PriorityQueue<>((a, b) -> Integer.compare(b[2], a[2]));
    for (int[] edge : optionalEdges) {
        maxHeap.offer(new int[]{edge[0], edge[1], edge[2]});
    }

    // Also, prepare a list of edges with possible upgrades (only for optional edges)
    List<int[]> upgradedEdges = new ArrayList<>();
    for (int[] edge : optionalEdges) {
        upgradedEdges.add(new int[]{edge[0], edge[1], edge[2] * 2});
    }

    // Now, we need to select edges to maximize the minimum strength
    // The strategy is to use K upgrades on the K largest optional edges (after upgrade)
    // Then, select the remaining edges in a way that connects the graph with maximum possible min strength

    // To do this, we can:
    // 1. Use K upgrades on the top K optional edges (sorted by upgraded strength)
    // 2. Then, run Kruskal's algorithm with all edges (must + upgraded + remaining optional)

    // Sort optional edges by upgraded strength descending
    upgradedEdges.sort((a, b) -> Integer.compare(b[2], a[2]));

    // Select top K edges to upgrade
    Set<Integer> upgradedIndices = new HashSet<>();
    List<int[]> selectedUpgraded = new ArrayList<>();
    for (int i = 0; i < upgradedEdges.size() && upgradeLeft > 0; i++) {
        selectedUpgraded.add(upgradedEdges.get(i));
        upgradedIndices.add(i);
        upgradeLeft--;
    }

    // Now, collect all edges: must edges + upgraded edges + remaining optional edges (original si)
    List<int[]> allEdges = new ArrayList<>();
    allEdges.addAll(mustEdges);
    allEdges.addAll(selectedUpgraded);

    // Add remaining optional edges (not upgraded)
    for (int i = 0; i < optionalEdges.size(); i++) {
        if (!upgradedIndices.contains(i)) {
            allEdges.add(optionalEdges.get(i));
        }
    }

    // Sort all edges by strength descending to maximize the minimum strength
    allEdges.sort((a, b) -> Integer.compare(b[2], a[2]));

    // Run Kruskal's algorithm to find the spanning tree
    UnionFind ufFinal = new UnionFind(nodeCount);
    List<Integer> strengths = new ArrayList<>();

    for (int[] edge : allEdges) {
        int u = edge[0];
        int v = edge[1];
        int s = edge[2];
        if (ufFinal.find(u) != ufFinal.find(v)) {
            ufFinal.union(u, v);
            strengths.add(s);
        }
        if (strengths.size() == nodeCount - 1) {
            break;
        }
    }

    if (strengths.size() < nodeCount - 1) {
        return -1; // no spanning tree
