        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];
        if (s < minStrength) {
            return false; // must edge is too weak
        }
        if (uf.find(u) != uf.find(v)) {
            uf.union(u, v);
            components--;
        }
    }

    // Now add optional edges, possibly upgrading them
    int upgradesUsed = 0;
    for (long[] edge : optionalEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];
        long upgradedS = s * 2;

        if (upgradesUsed < k && upgradedS >= minStrength) {
            // Prefer to upgrade if it helps
            if (uf.find(u) != uf.find(v)) {
