import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        int nodeCount = (int) n;
        int upgradeCount = (int) k;
        List<Edge> edgeList = new ArrayList<>();
        for (long[] e : edges) {
            int u = (int) e[0];
            int v = (int) e[1];
            int s = (int) e[2];
            int must = (int) e[3];
            edgeList.add(new Edge(u, v, s, must));
        }

        // Separate must and optional edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();
        for (Edge e : edgeList) {
            if (e.must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // First, check if must edges form a cycle (using Union-Find)
        UnionFind uf = new UnionFind(nodeCount);
        for (Edge e : mustEdges) {
            if (uf.find(e.u) == uf.find(e.v)) {
                return -1; // cycle detected with must edges
            }
            uf.union(e.u, e.v);
        }

        // Now, process optional edges, prioritizing higher strength edges (after possible upgrade)
        // We need to select edges that can increase the min strength as much as possible
        // Sort optional edges by their potential strength (s or 2*s)
        Collections.sort(optionalEdges, (a, b) -> {
            int aMax = a.s * 2;
            int bMax = b.s * 2;
            return Integer.compare(bMax, aMax); // descending order
        });

        // Use a modified Krusky's algorithm to select edges
        // We can upgrade up to k edges, choosing those that give the highest strength
        UnionFind ufFinal = new UnionFind(nodeCount);
        // First add all must edges
        for (Edge e : mustEdges) {
            ufFinal.union(e.u, e.v);
        }

        int upgradesUsed = 0;
        PriorityQueue<Edge> pq = new PriorityQueue<>((a, b) -> Integer.compare(a.s, b.s)); // min-heap to track min edge
        List<Edge> selectedEdges = new ArrayList<>();
        selectedEdges.addAll(mustEdges);

        for (Edge e : optionalEdges) {
            if (ufFinal.find(e.u) != ufFinal.find(e.v)) {
                // Decide whether to upgrade this edge
                int strength = e.s;
                if (upgradesUsed < upgradeCount) {
                    strength *= 2;
                    upgradesUsed++;
                }
                selectedEdges.add(new Edge(e.u, e.v, strength, 0));
                ufFinal.union(e.u, e.v);
                pq.add(new Edge(e.u, e.v, strength, 0));
            }
        }

        // Check if all nodes are connected
        if (ufFinal.getCount() != 1) {
            return -1;
        }

        // The stability is the min strength in the selected edges
        long minStrength = Long.MAX_VALUE;
        for (Edge e : selectedEdges) {
            if (e.s < minStrength) {
                minStrength = e.s;
            }
        }

        return minStrength;
    }

    static class Edge {
        int u, v, s, must;
        Edge(int u, int v, int s, int must) {
            this.u = u;
            this.v = v;
            this.s = s;
            this.must = must;
        }
    }

    static class UnionFind {
        private int[] parent;
        private int count;

        public UnionFind(int n) {
            parent = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        public int find(int p) {
            while (p != parent[p]) {
                parent[p] = parent[parent[p]];
                p = parent[p];
            }
            return p;
        }

        public void union(int p, int q) {
            int rootP = find(p);
            int rootQ = find(q);
            if (rootP == rootQ) return;
            parent[rootP] = rootQ;
            count--;
        }

        public int getCount() {
            return count;
        }
    }
}
