public static long solve(long n, long[][] edges, long k) {
    // Separate must and optional edges
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // Initialize Union-Find
    long[] parent = new long[(int)n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Function to find root
    long find(long u) {
        while (parent[(int)u] != u) {
            parent[(int)u] = parent[(int)(parent[(int)u])];
            u = parent[(int)u];
        }
        return u;
    }

    // Function to union two sets
    boolean union(long u, long v) {
        long rootU = find(u);
        long rootV = find(v);
        if (rootU == rootV) {
            return false;
        }
        parent[(int)rootV] = rootU;
        return true;
    }

    // First, process all must edges
    int mustCount = 0;
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        if (union(u, v)) {
            mustCount++;
        } else {
            // Must edges form a cycle, impossible to have spanning tree
            return -1;
        }
    }

    // If must edges already form a spanning tree (n-1 edges)
    if (mustCount == n - 1) {
        long minStrength = Long.MAX_VALUE;
        for (long[] edge : mustEdges) {
            minStrength = Math.min(minStrength, edge[2]);
        }
        return minStrength;
    }

    // Sort optional edges by descending strength (after potential upgrade)
    Collections.sort(optionalEdges, (a, b) -> {
        long aUpgraded = a[2] * 2;
        long bUpgraded = b[2] * 2;
        return Long.compare(bUpgraded, aUpgraded);
    });

    // Process optional edges to complete the spanning tree
    List<Long> selectedStrengths = new ArrayList<>();
    int upgradesUsed = 0;
    for (long[] edge : optionalEdges) {
        long u = edge[0];
        long v = edge[1];
        if (find(u) != find(v)) {
            // Decide whether to upgrade this edge
            if (upgradesUsed < k) {
                selectedStrengths.add(edge[2] * 2);
                upgradesUsed++;
            } else {
                selectedStrengths.add(edge[2]);
            }
            union(u, v);
            mustCount++;
            if (mustCount == n - 1) {
                break;
            }
        }
    }

    // Check if we have a spanning tree
    if (mustCount != n - 1) {
        return -1;
    }

    // Collect all edge strengths in the spanning tree
    List<Long> allStrengths = new ArrayList<>();
    for (long[] edge : mustEdges) {
        allStrengths.add(edge[2]);
    }
    allStrengths.addAll(selectedStrengths);

    // Find the minimum strength
    long minStrength = Long.MAX_VALUE;
    for (long s : allStrengths) {
        minStrength = Math.min(minStrength, s);
    }

    return minStrength;
