        ufMust.union(u, v);
    }

    // Now, build the MST with the must edges and optional edges (possibly upgraded)
    // We need to maximize the minimal strength in the MST
    // Binary search on the minimal strength
    long left = 1;
    long right = (long) 1e10;
    long result = -1;

    while (left <= right) {
        long mid = (left + right) / 2;
        if (isPossible(n, mustEdges, optionalEdges, k, mid)) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
