private static boolean isPossible(long n, List<long[]> mustEdges, List<long[]> optionalEdges, long k, long minStrength) {
    UnionFind uf = new UnionFind((int) n);
    // First, add all must edges
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        uf.union(u, v);
    }

    // Now, add optional edges that can meet the minStrength, possibly upgrading them
    int upgradesUsed = 0;
    // First, try to add edges without upgrading (if their original strength >= minStrength)
    for (long[] edge : optionalEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];
        if (s >= minStrength && uf.find(u) != uf.find(v)) {
            uf.union(u, v);
        }
    }

    if (uf.getCount() == 1) {
        return true;
    }

    // If not connected, try to use upgrades
    uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        uf.union(u, v);
    }

    upgradesUsed = 0;
    for (long[] edge : optionalEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];
        if (s * 2 >= minStrength) {
            if (uf.find(u) != uf.find(v)) {
                uf.union(u, v);
                upgradesUsed++;
            }
        }
    }

    if (uf.getCount() == 1 && upgradesUsed <= k) {
        return true;
    }

    // If still not connected, try a mix of upgraded and non-upgraded edges
    // Sort optional edges by max possible strength (upgraded first)
    optionalEdges.sort((a, b) -> {
        long aMax = Math.max(a[2], a[2] * 2);
        long bMax = Math.max(b[2], b[2] * 2);
        return Long.compare(bMax, aMax);
    });

    uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        uf.union(u, v);
    }

    upgradesUsed = 0;
    for (long[] edge : optionalEdges) {
        int u = (int) edge[0];
