        long s = edge[2];
        boolean upgraded = false;
        if (s * 2 >= minStrength && upgradesUsed < k) {
            if (uf.find(u) != uf.find(v)) {
                uf.union(u, v);
                upgradesUsed++;
                upgraded = true;
            }
        }
        if (!upgraded && s >= minStrength) {
            if (uf.find(u) != uf.find(v)) {
                uf.union(u, v);
            }
        }
    }

    return uf.getCount() == 1;
