    List<Edge> edgeList = new ArrayList<>();
    for (long[] edge : edges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        long must = edge[3];
        edgeList.add(new Edge(u, v, s, must));
    }

    // Separate must edges and optional edges
    List<Edge> mustEdges = new ArrayList<>();
    List<Edge> optionalEdges = new ArrayList<>();
    for (Edge e : edgeList) {
        if (e.must == 1) {
            mustEdges.add(e);
        } else {
            optionalEdges.add(e);
        }
    }

    // Check if must edges form a cycle (using Union-Find)
    UnionFind uf = new UnionFind(n);
    for (Edge e : mustEdges) {
        if (uf.find(e.u) == uf.find(e.v)) {
            return -1; // cycle detected
        }
        uf.union(e.u, e.v);
    }

    // Now, process optional edges with possible upgrades
    // Sort optional edges by descending order of s (original or doubled)
    // We want to pick edges with higher s first to maximize the minimal s
    Collections.sort(optionalEdges, (a, b) -> Long.compare(b.s, a.s));

    // Use Krusky's algorithm to pick the best edges
    // We can upgrade up to k edges (those with highest s after doubling)
    // So, first pick the top k edges to upgrade (if possible)
    List<Edge> upgradedEdges = new ArrayList<>();
    List<Edge> remainingEdges = new ArrayList<>();
    for (int i = 0; i < optionalEdges.size(); i++) {
        Edge e = optionalEdges.get(i);
        if (i < k) {
            upgradedEdges.add(new Edge(e.u, e.v, e.s * 2, e.must));
        } else {
            remainingEdges.add(e);
        }
    }

    // Combine all edges: mustEdges + upgradedEdges + remainingEdges
    List<Edge> allEdges = new ArrayList<>();
    allEdges.addAll(mustEdges);
    allEdges.addAll(upgradedEdges);
    allEdges.addAll(remainingEdges);

    // Sort all edges by descending s
    Collections.sort(allEdges, (a, b) -> Long.compare(b.s, a.s));

    // Run Krusky's algorithm to find the spanning tree with max minimal s
    UnionFind ufFinal = new UnionFind(n);
    long minS = Long.MAX_VALUE;
    int edgeCount = 0;

    for (Edge e : allEdges) {
        if (ufFinal.find(e.u) != ufFinal.find(e.v)) {
            ufFinal.union(e.u, e.v);
            minS = Math.min(minS, e.s);
            edgeCount++;
            if (edgeCount == n - 1) {
                break;
            }
        }
    }

    if (edgeCount != n - 1) {
        return -1;
    }

    return minS;
}

