    optionalEdges.sort((a, b) -> {
        long aMax = a[2] * 2;
        long bMax = b[2] * 2;
        return Long.compare(bMax, aMax);
    });

    // We need to select (n-1 - mustCount) edges from optional edges
    long remaining = n - 1 - mustCount;
    if (remaining < 0) {
        return -1; // Too many must edges
    }

    // Collect the selected edges' strengths
    List<Long> selectedStrengths = new ArrayList<>();
    long upgradesLeft = k;

    for (long[] edge : optionalEdges) {
        if (remaining <= 0) break;
        long u = edge[0];
        long v = edge[1];
        long rootU = find.apply(u);
        long rootV = find.apply(v);
        if (rootU != rootV) {
            parent[(int)rootV] = rootU;
            long strength = edge[2];
            if (upgradesLeft > 0) {
                strength *= 2;
                upgradesLeft--;
            }
            selectedStrengths.add(strength);
            remaining--;
        }
    }

    if (remaining > 0) {
        return -1; // Not enough edges to form spanning tree
    }

    // Now collect all strengths (must edges + selected optional edges)
    List<Long> allStrengths = new ArrayList<>();
    for (long[] edge : mustEdges) {
        allStrengths.add(edge[2]);
    }
    allStrengths.addAll(selectedStrengths);

    // Find the minimum strength
    long minStrength = Long.MAX_VALUE;
    for (long s : allStrengths) {
        if (s < minStrength) {
            minStrength = s;
        }
    }

    return minStrength;
}
