import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Convert input to more manageable types
        int numNodes = (int) n;
        int numEdges = edges.length;
        int upgradesLeft = (int) k;

        // Separate must and optional edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int must = (int) edge[3];
            Edge e = new Edge(u, v, s, must);
            if (must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // First, check if must edges form a cycle (using Union-Find)
        UnionFind uf = new UnionFind(numNodes);
        boolean hasCycle = false;
        for (Edge e : mustEdges) {
            if (uf.find(e.u) == uf.find(e.v)) {
                hasCycle = true;
                break;
            }
            uf.union(e.u, e.v);
        }
        if (hasCycle) {
            return -1;
        }

        // If must edges already form a spanning tree, return min strength
        if (uf.count == 1) {
            int minStrength = Integer.MAX_VALUE;
            for (Edge e : mustEdges) {
                minStrength = Math.min(minStrength, e.s);
            }
            return minStrength;
        }

        // Sort optional edges by descending strength (after potential upgrade)
        Collections.sort(optionalEdges, (a, b) -> {
            int aUpgraded = a.s * 2;
            int bUpgraded = b.s * 2;
            return Integer.compare(bUpgraded, aUpgraded);
        });

        // Now, try to add optional edges to complete the spanning tree
        // We want to maximize the minimum strength, so prioritize edges with higher possible strength
        PriorityQueue<Edge> maxHeap = new PriorityQueue<>((a, b) -> {
            int aStrength = a.upgraded ? a.s : a.s * 2;
            int bStrength = b.upgraded ? b.s : b.s * 2;
            return Integer.compare(bStrength, aStrength);
        });

        maxHeap.addAll(optionalEdges);

        List<Edge> selectedEdges = new ArrayList<>(mustEdges);
        int remaining = numNodes - 1 - mustEdges.size();

        while (remaining > 0 && !maxHeap.isEmpty()) {
            Edge e = maxHeap.poll();
            if (uf.find(e.u) != uf.find(e.v)) {
                // Decide whether to upgrade this edge
                if (!e.upgraded && upgradesLeft > 0) {
                    e.s *= 2;
                    e.upgraded = true;
                    upgradesLeft--;
                }
                selectedEdges.add(e);
                uf.union(e.u, e.v);
                remaining--;
            }
        }

        if (uf.count != 1) {
            return -1;
        }

        // Find the minimum strength in the selected edges
        int minStrength = Integer.MAX_VALUE;
        for (Edge e : selectedEdges) {
            minStrength = Math.min(minStrength, e.s);
        }

        return minStrength;
    }

    static class Edge {
        int u, v, s;
        boolean upgraded;
        int must;

        Edge(int u, int v, int s, int must) {
            this.u = u;
            this.v = v;
            this.s = s;
            this.must = must;
            this.upgraded = false;
        }
    }

    static class UnionFind {
        int[] parent;
        int[] rank;
        int count;

        UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union(int x, int y) {
            int xRoot = find(x);
            int yRoot = find(y);
            if (xRoot == yRoot) {
