public static long solve(long n, long[][] edges, long k) {
    // Separate must and non-must edges
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> nonMustEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            nonMustEdges.add(edge);
        }
    }

    // Sort non-must edges by descending strength (after potential upgrade)
    Collections.sort(nonMustEdges, (a, b) -> Long.compare(b[2] * 2, a[2] * 2));

    // Initialize DSU
    DSU dsu = new DSU((int) n);

    // First, add all must edges
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        dsu.union(u, v);
    }

    // If must edges already form cycles, return -1
    if (dsu.count != 1) {
        // Now try to connect using non-must edges
        // Sort non-must edges by descending original strength (for initial connection)
        Collections.sort(nonMustEdges, (a, b) -> Long.compare(b[2], a[2]));

        DSU tempDsu = new DSU((int) n);
        for (long[] edge : mustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            tempDsu.union(u, v);
        }

        int upgradesUsed = 0;
        long minStrength = Long.MAX_VALUE;

        // First pass: connect without upgrades if possible
        for (long[] edge : nonMustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long s = edge[2];
            if (tempDsu.union(u, v)) {
                minStrength = Math.min(minStrength, s);
            }
            if (tempDsu.count == 1) break;
        }

        if (tempDsu.count != 1) {
            return -1;
        }

        // Now, we can form a spanning tree, need to maximize min strength
        // Binary search the possible min strength
        long left = 1;
        long right = (long) 1e10;
        long result = -1;

        while (left <= right) {
            long mid = left + (right - left) / 2;
            if (isPossible((int) n, mustEdges, nonMustEdges, (int) k, mid)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }

    // All nodes are connected by must edges, now we can optionally add non-must edges
    // to improve the min strength
    long minStrength = Long.MAX_VALUE;
    for (long[] edge : mustEdges) {
        minStrength = Math.min(minStrength, edge[2]);
    }

    // Now try to add non-must edges (possibly upgraded) to improve min strength
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[2], b[2]));
    for (long[] edge : nonMustEdges) {
        pq.offer(new long[]{edge[0], edge[1], edge[2]});
    }

    int upgradesLeft = (int) k;
    while (!pq.isEmpty() && upgradesLeft > 0) {
        long[] edge = pq.poll();
        long upgradedStrength = edge[2] * 2;
        if (upgradedStrength > minStrength) {
            minStrength = Math.min(minStrength, upgradedStrength);
            upgradesLeft--;
        }
    }

    return minStrength;
}

private static boolean isPossible(int n, List<long[]> mustEdges, List<long[]> nonMustEdges, int k, long targetMin) {
    DSU dsu = new DSU(n);

    // Add must edges first
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        dsu.union(u, v);
    }

    int upgradesUsed = 0;

    // Add non-must edges that can meet the targetMin (possibly upgraded)
    for (long[] edge : nonMustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long s = edge[2];

        if (s >= targetMin) {
            dsu.union(u, v);
        } else if (s * 2 >= targetMin && upgradesUsed < k) {
            dsu.union(u, v);
            upgradesUsed++;
        }

        if (dsu.count == 1) break;
    }

    return dsu.count == 1;
}

static class DSU {
    int[] parent;
    int[] rank;
    int count;

    public DSU(int n) {
        parent = new int[n];
        rank = new int[n];
        count = n;
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public boolean union(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);
        if (xRoot == yRoot) {
            return false;
        }
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else if (rank[xRoot] > rank[yRoot]) {
            parent[yRoot] = xRoot;
        } else {
            parent[yRoot] = xRoot;
            rank[xRoot]++;
        }
        count--;
        return true;
    }
