            long v = edge[1];
            long s = edge[2];
            long must = edge[3];
            edgeList.add(new Edge(u, v, s, must));
        }

        // Separate must and optional edges
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();
        for (Edge e : edgeList) {
            if (e.must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // First, check if must edges form a cycle (using Union-Find)
        UnionFind uf = new UnionFind((int) n);
        for (Edge e : mustEdges) {
            if (uf.find((int) e.u) == uf.find((int) e.v)) {
                return -1; // cycle detected with must edges
            }
            uf.union((int) e.u, (int) e.v);
        }

        // Now, process optional edges
        // Sort optional edges in descending order of s (original strength)
        optionalEdges.sort((a, b) -> Long.compare(b.s, a.s));

        // We need to select (n-1 - mustEdges.size()) edges from optionalEdges
        // and upgrade top k edges (if possible) to maximize the min strength
        long needed = (n - 1) - mustEdges.size();
        if (needed < 0 || needed > optionalEdges.size()) {
            return -1; // not enough edges to form spanning tree
        }

        // Select top 'needed' edges from optionalEdges (after sorting)
        List<Edge> selectedOptional = new ArrayList<>();
        for (int i = 0; i < needed; i++) {
            selectedOptional.add(optionalEdges.get(i));
        }

        // Now, among selectedOptional, upgrade top min(k, selectedOptional.size()) edges
        selectedOptional.sort((a, b) -> Long.compare(b.s, a.s));
        for (int i = 0; i < Math.min(k, selectedOptional.size()); i++) {
            selectedOptional.get(i).s *= 2;
        }

        // Now, collect all edges in the spanning tree (must + selectedOptional)
        List<Edge> spanningTree = new ArrayList<>();
        spanningTree.addAll(mustEdges);
        spanningTree.addAll(selectedOptional);

