public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        int nodeCount = (int) n;
        int upgradeBudget = (int) k;
        List<Edge> allEdges = new ArrayList<>();
        List<Edge> mustEdges = new ArrayList<>();
        List<Edge> optionalEdges = new ArrayList<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int s = (int) edge[2];
            int must = (int) edge[3];
            Edge e = new Edge(u, v, s, must);
            allEdges.add(e);
            if (must == 1) {
                mustEdges.add(e);
            } else {
                optionalEdges.add(e);
            }
        }

        // First, check if must edges form a cycle
        UnionFind ufMust = new UnionFind(nodeCount);
        for (Edge e : mustEdges) {
            if (ufMust.union(e.u, e.v)) {
                // Cycle detected with must edges
                return -1;
            }
        }

        // Now, try to build the spanning tree with maximum min strength
        // Binary search on the possible min strength
        int left = 1;
        int right = (int) 1e5 * 2; // max possible strength after upgrade
        long result = -1;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (isPossible(nodeCount, mustEdges, optionalEdges, upgradeBudget, mid)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }

    private static boolean isPossible(int nodeCount, List<Edge> mustEdges, List<Edge> optionalEdges, int upgradeBudget, int targetMin) {
        UnionFind uf = new UnionFind(nodeCount);
        int usedUpgrades = 0;

        // First, add all must edges (they cannot be upgraded)
        for (Edge e : mustEdges) {
            if (e.s < targetMin) {
                return false; // must edge is below target, cannot upgrade
            }
            uf.union(e.u, e.v);
        }

        // Then, add optional edges that can meet target without upgrade
        for (Edge e : optionalEdges) {
            if (e.s >= targetMin) {
                uf.union(e.u, e.v);
            }
        }

        // If already connected, no need to use upgrades
        if (uf.count == 1) {
            return true;
        }

        // Now, try to use upgrades to meet target
        for (Edge e : optionalEdges) {
            if (e.s * 2 >= targetMin && e.s < targetMin) {
                if (usedUpgrades < upgradeBudget) {
                    uf.union(e.u, e.v);
                    usedUpgrades++;
                    if (uf.count == 1) {
                        break;
                    }
                }
            }
        }

        return uf.count == 1;
    }

