    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // Check if must edges form a cycle using Union-Find
    UnionFind uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // cycle detected with must edges
        }
        uf.union(u, v);
    }

    // Now process optional edges, sorted by descending strength (after potential upgrade)
    // We need to consider upgrading the strongest possible edges first
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> {
        long aUpgraded = a[2] * 2;
        long bUpgraded = b[2] * 2;
        return Long.compare(bUpgraded, aUpgraded); // max heap
    });

    for (long[] edge : optionalEdges) {
        pq.offer(edge);
    }

    // Use Krusky's algorithm to select edges, prioritizing upgraded edges
    int remainingUpgrades = (int) k;
    List<Long> selectedStrengths = new ArrayList<>();

    // Add must edges' strengths
    for (long[] edge : mustEdges) {
        selectedStrengths.add(edge[2]);
    }

    // Process optional edges
    while (!pq.isEmpty() && remainingUpgrades > 0) {
        long[] edge = pq.poll();
        int u = (int) edge[0];
        int v = (int) edge[1];
        if (uf.find(u) != uf.find(v)) {
            uf.union(u, v);
            selectedStrengths.add(edge[2] * 2);
            remainingUpgrades--;
        }
    }

    // Now add remaining optional edges without upgrading
    // Re-sort optional edges by original strength descending
    optionalEdges.sort((a, b) -> Long.compare(b[2], a[2]));
    for (long[] edge : optionalEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        if (uf.find(u) != uf.find(v)) {
            uf.union(u, v);
            selectedStrengths.add(edge[2]);
        }
    }

    // Check if all nodes are connected
    if (uf.getCount() != 1) {
        return -1;
    }

    // Find the minimum strength in selected edges
    long minStrength = Long.MAX_VALUE;
    for (long s : selectedStrengths) {
        if (s < minStrength) {
            minStrength = s;
        }
    }

    return minStrength;
}

