    }

    // Now, sort all edges by descending strength
    allEdges.sort((a, b) -> Long.compare(b[2], a[2]));

    // Use Krusky's algorithm to find the spanning tree with max minimal strength
    UnionFind uf = new UnionFind((int) n);
    long minStrength = Long.MAX_VALUE;
    int edgesAdded = 0;

    for (long[] edge : allEdges) {
        int u = (int) edge[0];
