    UnionFind uf = new UnionFind((int) n);
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        if (uf.find(u) == uf.find(v)) {
            return -1; // cycle detected in must edges
        }
        uf.union(u, v);
    }

    // Sort non-must edges by descending order of (original si, then upgraded si)
    nonMustEdges.sort((a, b) -> {
        long aUpgraded = a[2] * 2;
        long bUpgraded = b[2] * 2;
        if (Math.max(a[2], aUpgraded) != Math.max(b[2], bUpgraded)) {
            return Long.compare(Math.max(b[2], bUpgraded), Math.max(a[2], aUpgraded));
        }
        return Long.compare(b[2], a[2]);
    });

    // Now, select the best possible edges to maximize the minimal strength
    // We need to select (n-1 - mustEdges.size()) edges from nonMustEdges
    int edgesNeeded = (int) (n - 1 - mustEdges.size());
    if (edgesNeeded < 0) {
        return -1; // too many must edges
    }

    // We'll use a priority queue to track the minimal strength in the current spanning tree
    PriorityQueue<Long> minHeap = new PriorityQueue<>();
    for (long[] edge : mustEdges) {
        minHeap.add(edge[2]);
    }

    // Select edges from nonMustEdges, possibly upgrading some
    int upgradesLeft = (int) k;
    for (long[] edge : nonMustEdges) {
        if (edgesNeeded <= 0) {
            break;
        }
        long s = edge[2];
        long upgradedS = s * 2;
        long chosenS = (upgradesLeft > 0) ? Math.max(s, upgradedS) : s;
        if (upgradesLeft > 0 && upgradedS > s) {
            upgradesLeft--;
            chosenS = upgradedS;
        }
        minHeap.add(chosenS);
        edgesNeeded--;
    }

    if (edgesNeeded > 0) {
        return -1; // not enough edges to form spanning tree
    }

    // The minimal strength in the heap is our answer
    return minHeap.peek();
