    UnionFind ufMust = new UnionFind(nodeCount);
    for (Edge edge : mustEdges) {
        if (ufMust.union(edge.u, edge.v)) {
            // Already connected, cycle detected
            return -1;
        }
    }

    // If must edges are more than n-1, it's impossible (but since they are edges, not necessarily)
    // But since they must be in the spanning tree, and spanning tree has n-1 edges, must edges must be <= n-1

    // Now, we need to select optional edges to complete the spanning tree
    // We want to maximize the minimal strength in the tree, so we can use binary search

    // Binary search the minimal strength
    long left = 1;
    long right = (long) 1e10;
