    for (Edge edge : mustEdges) {
        if (edge.s < targetMin) {
            return false; // must edge is below target, cannot upgrade
        }
        uf.union(edge.u, edge.v);
    }

    // Then, add optional edges that can meet the target without upgrade (s >= target)
    for (Edge edge : optionalEdges) {
        if (edge.s >= targetMin) {
            uf.union(edge.u, edge.v);
        }
    }

    // If already connected, return true
    if (uf.getCount() == 1) {
        return true;
    }

    // Otherwise, try to use upgrades to meet the target
    // We need to select edges where s < targetMin but 2*s >= targetMin
    // Sort optional edges by 2*s descending to maximize the minimal strength
    List<Edge> upgradableEdges = new ArrayList<>();
    for (Edge edge : optionalEdges) {
        if (edge.s < targetMin && 2 * edge.s >= targetMin) {
            upgradableEdges.add(edge);
        }
    }

    // Sort by 2*s descending to get the highest possible minimal strength
    upgradableEdges.sort((a, b) -> Long.compare(b.s * 2, a.s * 2));

    UnionFind ufUpgrade = new UnionFind(nodeCount);
    // Add must edges first
    for (Edge edge : mustEdges) {
        ufUpgrade.union(edge.u, edge.v);
    }

    int upgradesUsed = 0;
    for (Edge edge : upgradableEdges) {
        if (upgradesUsed >= upgradeLimit) {
            break;
        }
        if (ufUpgrade.union(edge.u, edge.v)) {
            upgradesUsed++;
        }
    }

    // Now add remaining optional edges (s >= targetMin) that haven't been added yet
    for (Edge edge : optionalEdges) {
        if (edge.s >= targetMin) {
            ufUpgrade.union(edge.u, edge.v);
        }
    }

    return ufUpgrade.getCount() == 1 && upgradesUsed <= upgradeLimit;
