        long strength = edge[2];
        if (i < k) {
            strength *= 2; // upgrade
        }
        selectedStrengths.add(strength);
    }

    // If we couldn't select enough edges, return -1
    if (selectedStrengths.size() < needed) {
        return -1;
    }

    // The stability is the min between must edges and selected optional edges
    long minMust = Long.MAX_VALUE;
    for (long[] edge : mustEdges) {
