    // We need to maximize the minimal strength, so we should prefer higher strength edges
    // Also, we can upgrade up to k edges (those with highest potential after upgrade)

    // Create a list of possible edges (original or upgraded)
    List<long[]> allOptionalEdges = new ArrayList<>();
    for (long[] edge : optionalEdges) {
