        long v = edge[1];
        long s = edge[2];
        allOptionalEdges.add(new long[]{u, v, s, 0}); // original
        allOptionalEdges.add(new long[]{u, v, s * 2, 1}); // upgraded
    }

    // Sort all optional edges by strength descending
    Collections.sort(allOptionalEdges, (a, b) -> Long.compare(b[2], a[2]));

    // Now, select the best edges (original or upgraded) to connect the remaining components
    // We can use up to k upgraded edges (marked with 1)
    UnionFind ufFinal = new UnionFind((int) n);
