    List<Edge> candidates = new ArrayList<>();
    for (long[] edge : optionalEdges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        candidates.add(new Edge(u, v, s, false));
        candidates.add(new Edge(u, v, s * 2, true));
    }

    // Sort candidates in descending order of s
    Collections.sort(candidates, (a, b) -> Long.compare(b.s, a.s));

