    // We can use up to k upgrades (each upgrade is a candidate with upgraded=true)
    int upgradesUsed = 0;
    UnionFind ufFinal = new UnionFind(uf.parent.clone());

    for (Edge edge : candidates) {
        if (ufFinal.find((int) edge.u) == ufFinal.find((int) edge.v)) {
            continue; // skip to avoid cycle
        }
        if (edge.upgraded) {
            if (upgradesUsed >= k) {
                continue; // no more upgrades allowed
            }
            upgradesUsed++;
        }
        ufFinal.union((int) edge.u, (int) edge.v);
    }

    // Check if all nodes are connected
    if (ufFinal.getCount() != 1) {
        return -1;
    }

    // Now, find the minimum edge in the spanning tree
    // Rebuild the spanning tree with the selected edges
    // We need to track the edges in the spanning tree
    UnionFind ufTree = new UnionFind((int) n);
    List<Long> treeEdges = new ArrayList<>();

    // Add must edges first
    for (long[] edge : mustEdges) {
        int u = (int) edge[0];
