    private static boolean canAchieveStability(int n, List<long[]> mustEdges, List<long[]> optionalEdges, long k, long target) {
        UnionFind uf = new UnionFind(n);
        // First, add all must edges
        for (long[] edge : mustEdges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            uf.union(u, v);
        }

        // Now, add optional edges with strength >= target (possibly upgraded)
        long upgradesUsed = 0;
        for (long[] edge : optionalEdges) {
            long s = edge[2];
            int u = (int) edge[0];
            int v = (int) edge[1];

            if (s >= target) {
                if (uf.find(u) != uf.find(v)) {
                    uf.union(u, v);
                }
            } else if (s * 2 >= target && upgradesUsed < k) {
                if (uf.find(u) != uf.find(v)) {
                    uf.union(u, v);
                    upgradesUsed++;
                }
            }
        }

        return uf.count == 1;
    }

    static class UnionFind {
        int[] parent;
        int[] rank;
        int count;

        public UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) {
                return;
            }
            if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            count--;
        }
    }
