```java
import java.util.*;

public static long solve(long n, long[][] edges, long k) {
    // Separate must and optional edges
    List<long[]> mustEdges = new ArrayList<>();
    List<long[]> optionalEdges = new ArrayList<>();
    for (long[] edge : edges) {
        if (edge[3] == 1) {
            mustEdges.add(edge);
        } else {
            optionalEdges.add(edge);
        }
    }

    // Check if must edges form a cycle (using Union-Find)
    long[] parent = new long[(int)n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    long mustCount = 0;
    for (long[] edge : mustEdges) {
        long u = edge[0];
        long v = edge[1];
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU == rootV) {
            return -1; // cycle detected with must edges
        }
        parent[(int)rootU] = rootV;
        mustCount++;
    }

    // Now process optional edges, prioritizing higher strength edges (after possible upgrade)
    // We need to select (n-1 - mustCount) edges from optional edges
    // Sort optional edges in descending order of max possible strength (either s or 2*s)
    Collections.sort(optionalEdges, (a, b) -> {
        long aMax = Math.max(a[2], 2 * a[2]);
        long bMax = Math.max(b[2], 2 * b[2]);
        return Long.compare(bMax, aMax);
    });

    // Use Union-Find to build the spanning tree
    long selected = 0;
    long upgradesUsed = 0;
    PriorityQueue<long[]> minHeap = new PriorityQueue<>((a, b) -> Long.compare(a[2], b[2]));

    // First, add all must edges to the heap
    for (long[] edge : mustEdges) {
        minHeap.add(new long[]{edge[0], edge[1], edge[2]});
    }

    // Then process optional edges
    for (long[] edge : optionalEdges) {
        long u = edge[0];
        long v = edge[1];
        long s = edge[2];
        long rootU = find(parent, u);
        long rootV = find(parent, v);
        if (rootU != rootV) {
            // Decide whether to upgrade this edge
            long strength = s;
            if (upgradesUsed < k) {
                strength = 2 * s;
                upgradesUsed++;
            }
            parent[(int)rootU] = rootV;
            selected++;
            minHeap.add(new long[]{u, v, strength});
        }
        if (selected + mustCount == n - 1) {
            break;
        }
    }

    // Check if we have a spanning tree
    if (selected + mustCount != n - 1) {
        return -1;
    }

    // The stability is the minimum strength in the spanning tree
    long minStrength = Long.MAX_VALUE;
    while (!minHeap.isEmpty()) {
        long[] edge = minHeap.poll();
        minStrength = Math.min(minStrength, edge[2]);
    }

    return minStrength;
}

private static long find(long[] parent, long node) {
    if (parent[(int)node] != node) {
        parent[(int)node] = find(parent, parent[(int)node]);
    }
    return parent[(int)node];
}
